:root {
  --bg: #fafafa;
  --text: #111111;
  --surface: #ffffff;
  --accent: #3b82f6;
  --border: rgba(0, 0, 0, 0.12);
  --accent-contrast: #ffffff;
  --panel-shadow: 0 1px 2px rgb(0 0 0 / 0.06);
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0b0b0c;
    --text: #f3f4f6;
    --surface: #16181a;
    --accent: #60a5fa;
    --border: rgba(255, 255, 255, 0.14);
    --accent-contrast: #0b0b0c;
    --panel-shadow: 0 1px 2px rgb(0 0 0 / 0.4);
  }
}

:root:where(.theme-dark) {
  --bg: #0b0b0c;
  --text: #f3f4f6;
  --surface: #16181a;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.14);
  --accent-contrast: #0b0b0c;
  --panel-shadow: 0 1px 2px rgb(0 0 0 / 0.4);
}

html, body { height: 100%; }
body {
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
  margin: 0;
  line-height: 1.6;
  background: var(--bg);
  color: var(--text);
  display: grid;
  place-items: center;
  padding: 2rem;
}

.panel {
  background: var(--surface);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 1.25rem;
  box-shadow: var(--panel-shadow);
  max-width: 520px;
}

.btn {
  background: var(--accent);
  color: var(--accent-contrast);
  border: 0;
  padding: .5rem .9rem;
  border-radius: .6rem;
  font-weight: 600;
}
